                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="updates" fill="#3399ff" />
              </BarChart>
            </div>
          </section>


          <section className="top-repos">
            <h2 className="blue-title">Top repository</h2>
