          new Repository({
            id: "2", name: "NodeAPI", full_name: "unix69/NodeAPI", stars: 15,
            forks: 5, open_issues_count: 2, clone_url: "https://github.com/unix69/NodeAPI.git",
            owner: { login: "unix69", html_url: "https://github.com/unix69", avatar_url: "" },
            created_at: "2023-02-01T00:00:00Z", updated_at: "2023-03-10T12:00:00Z"
