          new Repository({
            id: "3", name: "Portfolio", full_name: "unix69/Portfolio", stars: 40,
            forks: 12, open_issues_count: 0, clone_url: "https://github.com/unix69/Portfolio.git",
            owner: { login: "unix69", html_url: "https://github.com/unix69", avatar_url: "" },
            created_at: "2022-12-01T00:00:00Z", updated_at: "2023-02-15T12:00:00Z"
          })
        ];

        // Aggiungiamo lingue fittizie
        mockRepos[0].languages = ["JavaScript", "HTML", "CSS"];
        mockRepos[1].languages = ["Node.js", "JavaScript"];
        mockRepos[2].languages = ["HTML", "CSS"];

        setRepos(mockRepos);
        computeLanguageStats(mockRepos);
        computeUpdateTimeline(mockRepos);

      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    fetchRepos();
  }, []);

  const computeLanguageStats = (repos) => {
    const langCounts = {};
    repos.forEach(repo => repo.languages.forEach(lang => {
      langCounts[lang] = (langCounts[lang] || 0) + 1;
    }));
    const data = Object.keys(langCounts).map(lang => ({
      name: lang,
      value: langCounts[lang]
    }));
    setLangData(data);
  };

  const computeUpdateTimeline = (repos) => {
    const timeline = {};
    repos.forEach(repo => {
      const month = repo.lastUpdate.toISOString().slice(0, 7);
      timeline[month] = (timeline[month] || 0) + 1;
    });
    const data = Object.keys(timeline).sort().map(month => ({
      month,
      updates: timeline[month]
    }));
    setUpdateData(data);
  };

  const filteredRepos = repos.filter(r => r.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <main className="repositories-page">
      <h1>Repositories Overview</h1>

      <section className="intro-section">
        <p>
          Modalità simulata attiva: puoi vedere le repository, grafici e statistiche senza fare fetch reale da GitHub.
        </p>
      </section>

      <section className="search-section">
        <input
          type="text"
          placeholder="Cerca repository..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </section>

      {loading && <p style={{textAlign:"center"}}>Caricamento repository...</p>}

      {!loading && filteredRepos.length > 0 && (
        <>
          {/* Lista repository */}
          <section className="repos-summary">
            <h2 className="blue-title">Elenco repository</h2>
            <div className="repo-names">
              {filteredRepos.map(r => (
                <span key={r.id} className="repo-name-pill">{r.name}</span>
              ))}
            </div>
            <p>
              Totale repository: {filteredRepos.length} | 
              Stars totali: {filteredRepos.reduce((sum,r)=>sum+r.stars,0)} | 
              Forks totali: {filteredRepos.reduce((sum,r)=>sum+r.forks,0)}
            </p>
          </section>

          {/* Grafici */}
          <section className="charts-section">
            <div className="chart-wrapper">
              <h2 className="orange-title">Linguaggi più usati</h2>
              <PieChart width={400} height={300}>
                <Pie
                  data={langData}
                  dataKey="value"
                  nameKey="name"
                  cx="50%"
                  cy="50%"
                  outerRadius={100}
                  label
                >
                  {langData.map((entry,index) => (
                    <Cell key={index} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Legend />
              </PieChart>
            </div>

            <div className="chart-wrapper">
              <h2 className="blue-title">Attività aggiornamenti</h2>
              <BarChart width={500} height={300} data={updateData}>
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="updates" fill="#3399ff" />
              </BarChart>
            </div>
          </section>
        </>
      )}

      {!loading && filteredRepos.length === 0 && (
        <p style={{textAlign:"center"}}>Nessuna repository trovata.</p>
      )}
    </main>
  );
}
